function normalizeDelay(value) {
    // Chuyển sang số (parseFloat an toàn hơn parseInt với số có dấu chấm)
    var num = parseFloat(value);

    // Nếu không phải số, hoặc là NaN, thì trả về 0
    if (isNaN(num)) {
        return 0;
    }

    // Làm tròn xuống để bỏ phần thập phân
    num = Math.floor(num);

    // Giới hạn trong khoảng 0–60
    if (num < 0) num = 0;
    if (num > 60) num = 60;

    return num;
}
