// ===============================
// Utils
// ===============================

// convert HH:mm:ss -> ms trong ngày
function timeToMs(t) {
    var p = t.split(":");
    return (
        parseInt(p[0], 10) * 3600000 +
        parseInt(p[1], 10) * 60000 +
        parseInt(p[2], 10) * 1000
    );
}

// ===============================
// 1. Check 1 key
// ===============================
function checkKeyCondition(cond, deviceState) {
    if (!deviceState) return false;
    var v = deviceState[cond.key];
    if (typeof v !== "number") return false;
    if (cond.operator === "=") {
        return v === cond.value;
    }
    if (cond.operator === "RANGE") {
        if (typeof cond.min !== "number" || typeof cond.max !== "number") {
            return false;
        }
        if (cond.mode === "INSIDE") {
            return v >= cond.min && v <= cond.max;
        }
        if (cond.mode === "OUTSIDE") {
            return v < cond.min || v > cond.max;
        }
    }
    return false;
}

// ===============================
// 2. Check device
// ===============================
function checkDevice(deviceRule, stateMap) {

    var deviceState = stateMap[deviceRule.entityName];

    if (!deviceState) return false;

    var triggers = deviceRule.dataTrigger;

    if (!triggers || !triggers.length) return false;

    for (var i = 0; i < triggers.length; i++) {

        if (!checkKeyCondition(triggers[i], deviceState)) {
            return false;
        }
    }

    return true;
}
// ===============================
// 3. Check timer (bitmask)
// ===============================
function checkTimer(timer, metadata, nowDayMs, todayMask) {

    if (!timer || timer.activeTimer !== true) {
        return null;
    }

    // // ưu tiên dùng flag_timer nếu node trước đã tính
    // if (metadata && metadata.flag_timer != null) {
    //     return metadata.flag_timer === "true";
    // }
    var triggers = timer.triggers;
    if (!triggers || !triggers.length) return false;
    var window = 1000;
    for (var i = 0; i < triggers.length; i++) {
        var t = triggers[i];
        if (!(t.repeat & todayMask)) {
            continue;
        }
        var triggerMs = timeToMs(t.time);
        var diff = nowDayMs - triggerMs;
        if (diff < 0) diff += 86400000;
        if (diff <= window) {
            return true;
        }
    }
    return false;
}
// ===============================
// 4. Evaluate Rule
// ===============================
function evaluateRule(data, metadata) {
    if (data.ss_status !== 1) {
        return false;
    }
    var logic = (data.ss_logic || "AND").toUpperCase();
    var isAND = logic === "AND";
    var now = new Date();

    var offset = 7 * 3600000;

    var nowDayMs = (now.getTime() + offset) % 86400000;

    // metadata.nowUTC = now.toISOString();
    // metadata.nowVN  = new Date(now.getTime() + offset).toISOString();
    // metadata.nowDayMs = nowDayMs;

    // Mon=0 ... Sun=6
    var day = (now.getUTCDay() + 6) % 7;
    var todayMask = 1 << day;
    // =====================
    // VALIDITY PERIOD
    // =====================
    // var validityOK = checkValidity(
    //     data.ss_validityPeriod,
    //     nowDayMs,
    //     todayMask
    // );
    // if (!validityOK) return false;
    // =====================
    // DEVICE CHECK
    // =====================
    for (var i = 0; i < data.dataResponse.length; i++) {
        var deviceResult = checkDevice(
            data.dataResponse[i].data,
            data
        );
        if (isAND && !deviceResult) return false;

        if (!isAND && deviceResult) return true;
    }

    // =====================
    // TIMER CHECK
    // =====================

    var timerResult = checkTimer(
        data.ss_inputTimer,
        metadata,
        nowDayMs,
        todayMask
    );

    if (timerResult !== null) {
        if (isAND && !timerResult) return false;
        if (!isAND && timerResult) return true;
    }
    return isAND;
}

return evaluateRule(msg, metadata);

