        var h = (time.charCodeAt(0)-48)*10 + (time.charCodeAt(1)-48);
        var m = (time.charCodeAt(3)-48)*10 + (time.charCodeAt(4)-48);
        var minutes = h * 60 + m;
        var repeat = t.repeat;
        // nếu lặp cả tuần
        if (repeat === 127||repeat === 0) {
            result.push({
                type: "All_" + minutes
            });
            continue;
        }
        // check từng bit
        for (var d = 0; d < 7; d++) {
            if (repeat & DAY_BITS[d]) {
                result.push({
                    type: DAY_NAMES[d] + "_" + minutes
                });
